create table dirkspzm32.isi_event (
    sid          varchar2(2 char) not null enable,
    firma_nr     number(6, 0) not null enable,
    event_id     number(*, 0) not null enable,
    event_cfg_id number(*, 0) not null enable,
    obj_rep_name varchar2(100 char),
    obj_names    varchar2(255 char) not null enable,
    operators    varchar2(50 char) not null enable,
    obj_values   varchar2(500 char) not null enable
);

alter table dirkspzm32.isi_event
    add constraint pk_isi_event
        primary key ( sid,
                      firma_nr,
                      event_id )
            using index enable;


